create table if not exists hr_field_attendance (id uuid default random_uuid() primary key, tenant_id varchar(64) not null default 'default', work_order_id uuid, employee_id uuid, employee_name varchar(120), attendance_date date, check_in_time timestamp with time zone, check_out_time timestamp with time zone, location varchar(240), remark varchar(500), created_at timestamp with time zone not null default current_timestamp, updated_at timestamp with time zone not null default current_timestamp, created_by varchar(64), updated_by varchar(64));
create table if not exists maintenance_plans (id uuid default random_uuid() primary key, tenant_id varchar(64) not null default 'default', contract_id uuid, asset_id uuid, plan_name varchar(180), status varchar(40), planned_date date, created_at timestamp with time zone not null default current_timestamp, updated_at timestamp with time zone not null default current_timestamp, created_by varchar(64), updated_by varchar(64));
create index if not exists idx_hr_field_attendance_work_order on hr_field_attendance(work_order_id);
create index if not exists idx_maintenance_plans_contract on maintenance_plans(contract_id);
create index if not exists idx_maintenance_plans_asset on maintenance_plans(asset_id);
